  enable = true

  tags = {
    Compliance = "SOC2"
  }
}

resource "aws_s3_bucket_policy" "guardduty_logs" {
  bucket = aws_s3_bucket.guardduty.bucket
  policy = data.aws_iam_policy_document.guardduty_logs.json
}

