    { Name = "${var.environment}-vpc" }
  )
}

resource "aws_security_group" "sg" {
  name        = var.name
  description = var.description

  vpc_id      = var.vpc_id
  ingress     = [/* ... */]

  tags = merge(
    local.required_tags,
    { Name = "${var.environment}-security-group" }
  )
}
```

